INSERT INTO industries (industry_id, name, description) VALUES (1, '農業・林業', '農業・林業分野では、農作物の栽培や家畜の飼育を行う農業従事者（農家）、森林の育成・管理や木材の伐採を行う林業従事者（林家）が中心です。その他、農業機械のオペレーター、品種改良を行う研究者、農業資材の販売・開発、食品加工、森林保全、木材加工、バイオマス発電関連の仕事など多岐にわたります。');
INSERT INTO industries (industry_id, name, description) VALUES (2, '漁業・水産業', '漁業・水産業には、主に以下の仕事が存在します。1. 漁師: 漁船を操縦し、魚介類を捕獲、漁具の管理を行います。2. 水産養殖業: 魚や貝などの稚魚育成、餌やり、水質・健康管理を通じて水産物を育てます。3. 水産加工業: 捕獲・養殖された魚介類を、鮮魚から加工品（冷凍、缶詰、練り物など）へと処理し、品質管理を行います。4. 流通・販売業: 市場での仕入れ、仲卸、小売を通じて水産物を消費者に届けます。5. 水産研究・技術開発: 資源管理、養殖技術の改良、環境保護などに関する研究を行います。');
INSERT INTO industries (industry_id, name, description) VALUES (3, '鉱業・採石業・砂利採取業', '鉱業・採石業・砂利採取業には、資源探査を行う地質調査員、重機を操作して採掘・運搬を行うオペレーター、発破技士、採掘物の選別・加工を行う生産技術者、設備の維持管理を担う保全担当者、そして現場の安全管理や環境保全を担う専門職などが存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (4, '食料品製造業', '食料品製造業には、食品の生産ラインを管理する「製造・生産管理」、製品の品質と安全性を確保する「品質管理」、新商品の開発や既存製品の改良を行う「研究開発」といった職種があります。その他、生産設備の維持管理を行う「設備保全」、原材料を仕入れる「資材調達」、製品を販売する「営業・マーケティング」なども重要な役割です。');
INSERT INTO industries (industry_id, name, description) VALUES (5, '繊維・衣服・皮革製造業', '繊維・衣服・皮革製造業では、ファッションデザイナーやパターンナーとして製品のデザイン・企画を行います。製造現場では、縫製・裁断・染色・皮革加工などの技術者が製品を形にし、生産管理者や品質管理者が工程全体を統括します。また、新素材や加工技術の研究開発、完成品の営業・販売といった職種も存在し、多様な専門性が求められます。');
INSERT INTO industries (industry_id, name, description) VALUES (6, '木材・紙・印刷業', '木材・紙・印刷業には、森林管理、木材加工、製材、家具・建材製造などの木材関連職、パルプ・製紙、紙製品製造、研究開発などの製紙関連職、そして印刷オペレーター、プリプレス（ DTP 、製版）、ポストプレス（製本、加工）、印刷営業、企画などの印刷関連職があります。');
INSERT INTO industries (industry_id, name, description) VALUES (7, '化学工業（医薬品・化粧品含む）', '化学工業では、研究開発（新素材・医薬品・化粧品開発）、製造（プラント運転・品質管理）、営業・マーケティング（製品販売・市場開拓）、技術サービス（顧客サポート・技術指導）、生産技術（工程改善・効率化）などの職種が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (8, '石油・プラスチック・ゴム製品製造業', '石油・プラスチック・ゴム製品製造業には、原材料から最終製品に至るまで多岐にわたる仕事が存在します。主な職種としては、新たな素材や製品を開発する「研究開発（化学者、材料科学者）」、効率的かつ安全に製品を生産するための工程を管理し改善する「生産技術・製造オペレーター」、製品の品質を保証する「品質管理」、生産設備を適切に維持・管理する「設備保全」、そして顧客に製品を提案し販売する「営業・マーケティング」などがあります。専門的な技術知識と安全管理能力が求められる分野です。');
INSERT INTO industries (industry_id, name, description) VALUES (9, 'セラミックス・ガラス・土石製品製造業', 'セラミックス・ガラス・土石製品製造業には、原材料の調合、成形、焼成、加工、品質管理といった製造工程に携わる技術職・技能職が多く存在します。具体的には、生産ラインオペレーター、品質管理担当、設備保全エンジニアなどが挙げられます。また、新素材や製造技術の研究開発職、生産計画を管理する職、製品の営業・マーケティング職も重要な役割を担います。');
INSERT INTO industries (industry_id, name, description) VALUES (10, '鉄鋼・金属製品製造業', '鉄鋼・金属製品製造業では、鉄鉱石などの原材料から自動車、建設、家電などに使われる様々な鉄鋼製品や金属部品を製造します。主な仕事には、高炉や圧延機などの大型設備を操作し製品を生産する「製造・生産技術職」、生産設備の保守・点検を行う「設備保全職」、製品の品質を検査・管理する「品質管理職」、新たな素材や加工方法を開発する「研究開発職」、顧客への製品提案や販売を手がける「営業職」、生産計画の策定や原材料の調達・物流を担う「生産管理・SCM職」などがあります。');
INSERT INTO industries (industry_id, name, description) VALUES (11, '機械製造業', '機械製造業では、製品の企画・設計・開発を行う「機械設計エンジニア」「開発エンジニア」、実際の製造プロセスを管理・改善する「生産技術者」「製造オペレーター」、製品の品質を保証する「品質管理・品質保証」、顧客への提案・販売を行う「営業職」、そして納入後の機械の保守・修理を担当する「サービスエンジニア」など、多岐にわたる専門職が活躍しています。');
INSERT INTO industries (industry_id, name, description) VALUES (12, '電気・電子・半導体製造業', '電気・電子・半導体製造業では、新製品の企画・開発を行う研究開発、半導体や電子部品の回路を設計するエンジニア、製造ラインの工程を管理・改善する生産技術者、品質を保証する品質管理、設備のメンテナンスを行う保全員、そして国内外への製品販売・技術サポートを行う営業・FAEなど、多岐にわたる専門職が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (13, '自動車・輸送機器製造業', '自動車・輸送機器製造業では、車両や部品の研究開発（設計、実験、材料、ソフトウェア）、生産技術や製造、品質管理といったものづくりの中核を担う職種が多数存在します。また、国内外への営業・マーケティング、部品調達や物流を管理するサプライチェーンマネジメント、さらには人事、経理、情報システムといった管理部門も不可欠です。');
INSERT INTO industries (industry_id, name, description) VALUES (14, '精密機器・光学機器製造業', '精密機器・光学機器製造業では、レンズやセンサーの光学設計・機構設計・回路設計、半導体製造装置や医療機器などの開発、それらの製造技術・品質管理・生産管理、そして国内外への営業、完成品の保守・サービスといった専門的な仕事が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (15, 'エネルギー・電力・ガス・水道業', 'エネルギー・電力・ガス・水道業では、発電所の運転・保守、電力系統の管理、ガス・水道設備の設計・建設・保守、資源開発、顧客サービス、再生可能エネルギー技術開発など、多岐にわたる専門職が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (16, '建設・土木業', '建設・土木業では、道路、橋、建物などのインフラ整備において、設計・計画を担う土木設計技術者、現場での工程・品質・安全を管理する施工管理技士、そして実際の建設作業を遂行する建設作業員などが活躍しています。');
INSERT INTO industries (industry_id, name, description) VALUES (17, '不動産業', '不動産業界には、不動産の売買や賃貸を仲介する営業職、物件を管理するプロパティマネージャー、新しい不動産を企画・開発するデベロッパー、不動産の価値を評価する鑑定士、不動産投資を専門とするファンドマネージャーなどが存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (18, '情報通信業（IT・ソフトウェア・通信）', '情報通信業では、ソフトウェア開発（プログラマー、システムエンジニア、Web開発者）、インフラ構築・運用（インフラエンジニア、ネットワークエンジニア）、データ分析（データサイエンティスト）、ITコンサルティング、プロジェクトマネジメント、セキュリティ対策、IT営業、テクニカルサポートなど多岐にわたる仕事が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (19, '金融業・保険業', '金融業・保険業では、銀行で個人や企業向け融資・預金業務を行うバンカー、資産運用会社で株式や債券の運用を行うファンドマネージャー、証券会社で顧客の投資相談に乗る証券アナリストや営業担当、保険会社で保険商品の開発や引受を行うアクチュアリーやアンダーライター、保険金支払いを担当する損害調査人などが活躍しています。');
INSERT INTO industries (industry_id, name, description) VALUES (20, '商社・卸売業', '商社・卸売業では、国内外の多様な商品を取引し、顧客とサプライヤーを繋ぐ役割を担います。主な仕事として、商品の仕入れ・販売を行う「営業職」、輸出入の手続きや物流を管理する「貿易実務・ロジスティクス職」、市場調査に基づき商品戦略を立てる「マーケティング・商品企画職」などがあります。グローバルな視点と交渉力が求められます。');
INSERT INTO industries (industry_id, name, description) VALUES (21, '小売業・EC・流通業', '小売業・EC・流通業には、店舗での販売・運営（店長、販売員）、ECサイトの企画・運用（ECサイト運営、デジタルマーケター）、物流・サプライチェーン管理（倉庫作業員、配送ドライバー、ロジスティクス担当）、商品仕入れ・マーチャンダイジング、カスタマーサービスなど多岐にわたる仕事が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (22, '運輸・物流・倉庫業', '運輸・物流・倉庫業では、トラック運転手、倉庫作業員（入出荷・ピッキング）、フォークリフトオペレーター、配達員、そして全体の物流プロセスを最適化するロジスティクス管理者などが活躍しています。商品の運搬から保管、配送までを担う重要な仕事です。');
INSERT INTO industries (industry_id, name, description) VALUES (23, '宿泊・観光業', '宿泊・観光業には、ホテルや旅館でのフロント、客室サービス、レストラン業務、旅行会社でのツアー企画、販売、手配、テーマパークや観光施設での運営・案内業務、観光バスやタクシーでの送迎業務など、顧客の旅行体験を豊かにするための多岐にわたる仕事が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (24, '飲食・フードサービス業', '飲食・フードサービス業には、料理を調理する調理師・シェフ、お客様への接客や配膳を行うホールスタッフ、ドリンクを提供するバリスタ、店舗運営全般を管理する店長・マネージャー、食材管理や仕込みを担当するキッチンスタッフなどが存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (25, '医療・福祉・介護業', '医療・福祉・介護業には、医師、看護師、薬剤師などの医療専門職、社会福祉士、精神保健福祉士などの福祉専門職、介護福祉士、ケアマネジャーなどの介護専門職、およびこれらを支える事務職などが存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (26, '教育・学習支援業', '教育・学習支援業には、幼稚園から大学までの教員、塾や予備校の講師、家庭教師といった直接指導を行う職種のほか、教育コンテンツ開発、企業研修トレーナー、教育コンサルタント、学習支援員など、多様な専門職が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (27, '研究開発・学術機関', '研究開発・学術機関では、新たな知識や技術の探求・創造を行います。具体的な職種としては、大学や研究所における研究者、開発者、大学教員、技術者などが挙げられます。実験やデータ分析、論文執筆、教育活動などが主な業務です。');
INSERT INTO industries (industry_id, name, description) VALUES (28, '広告・出版・マスコミ・エンタメ業', '広告・出版・マスコミ・エンタメ業には、広告の企画・制作、書籍・雑誌の編集、テレビ・ラジオ・Webニュースの制作・記者、映画・音楽・舞台の制作・プロモーション、芸能マネジメントなど、クリエイティブなコンテンツを生み出し、世の中に届ける多様な職種が存在します。');
INSERT INTO industries (industry_id, name, description) VALUES (29, 'デザイン・アート・クリエイティブ業', 'デザイン・アート・クリエイティブ業では、グラフィックデザイナー、Webデザイナー、UI/UXデザイナー、イラストレーター、映像クリエイター、コピーライター、フォトグラファーなどが活躍し、視覚的な表現やアイデアで人々に感動や情報を届けます。');
INSERT INTO industries (industry_id, name, description) VALUES (30, 'スポーツ・レジャー・イベント業', 'スポーツ・レジャー・イベント業には、スポーツ選手の育成や施設運営、イベントの企画・設営、テーマパークや宿泊施設での接客、旅行商品の販売など多岐にわたる仕事が存在します。具体的には、スポーツトレーナー、スタジアム運営スタッフ、イベントプロデューサー、ホテル・旅館のコンシェルジュ、旅行カウンセラーなどが挙げられます。');
INSERT INTO industries (industry_id, name, description) VALUES (31, '官公庁・行政・自治体', '官公庁・行政・自治体では、国民や住民の生活を支える多岐にわたる仕事が存在します。具体的には、政策の企画・立案、予算の執行、許認可業務を行う「一般事務職」のほか、土木、建築、医療、福祉、教育などの分野で専門知識を活かす「技術職・専門職」、また国民の安全を守る「公安職（警察官、消防官）」などがあります。これらを通じて社会基盤の整備や公共サービスの提供に貢献します。');
INSERT INTO industries (industry_id, name, description) VALUES (32, '防衛・警察・消防', '防衛分野では、自衛官として国の安全保障や災害派遣に従事します。警察分野では、警察官が治安維持、犯罪捜査、交通安全などを担当します。消防分野では、消防士が火災消火、人命救助、救急活動などを行います。');
INSERT INTO industries (industry_id, name, description) VALUES (33, '法律・会計・コンサルティング業', '法律・会計・コンサルティング業では、弁護士が法的な紛争解決や契約作成を、公認会計士や税理士が企業の財務健全性評価や税務申告を担います。また、コンサルタントは経営戦略、IT導入、組織改革など専門知識を活かし、企業や組織の課題解決と成長を支援します。');
INSERT INTO industries (industry_id, name, description) VALUES (34, '宗教・非営利・NPO・NGO', '宗教・非営利・NPO・NGO分野には、宗教施設の運営や儀式を司る聖職者、社会課題解決を目指すNPO・NGOの活動を推進する職種があります。具体的には、プロジェクトの企画・運営、資金調達、広報、ボランティア管理、地域連携、そして福祉、教育、国際協力などの分野で直接支援を提供する専門スタッフなどが含まれます。組織を支える事務・経理・人事などのバックオフィス業務も重要です。');
INSERT INTO industries (industry_id, name, description) VALUES (35, '家事・個人サービス業（家政・美容・清掃など）', '家事・個人サービス業では、人々の生活を支え、快適にする多様な仕事が存在します。具体的には、家庭内での家事全般や育児をサポートする家政婦やベビーシッター、高齢者の生活を支援する訪問介護員、また、髪のカットやセットを行う美容師、肌のケアをするエステティシャン、爪の手入れをするネイリストといった美に関する専門職、さらには住宅やオフィス、商業施設などの清掃を行う清掃員やハウスクリーニング専門家などが挙げられます。');
INSERT INTO industries (industry_id, name, description) VALUES (36, '環境・リサイクル・サステナビリティ関連業', '環境・リサイクル・サステナビリティ関連業では、企業や自治体の環境規制遵守や持続可能性戦略を助言する環境コンサルタント、廃棄物の再資源化技術を開発・運用するリサイクル技術者、組織内でサステナビリティ推進やESG報告を行う専門家、再生可能エネルギー導入支援、環境教育・広報など、多岐にわたる職種があり、持続可能な社会の実現に貢献します。');
INSERT INTO industries (industry_id, name, description) VALUES (37, '宇宙・航空・先端科学産業', '航空機、ロケット、衛星などの設計・開発エンジニア、先進材料やAI、ロボット工学といった先端技術の研究開発者、さらにシステム統合、データ解析、運航管理などの専門職が存在します。');
